INSERT INTO `script_texts` (`entry`, `content_default`, `sound`, `type`, `language`, `emote`, `comment`) VALUES
(-1999962, 'More meat to devour!', 60590, 0, 0, 0, 'Stormwrought Ruins - Dagar the Glutton - Aggro'),
(-1999963, 'The hunger... never ends...', 60591, 0, 0, 0, 'Stormwrought Ruins - Dagar the Glutton - Death'),
(-1999964, 'Yet again do the forces of darkness seek to lay claim to my throne. Stormwrought will not fall into your hands, fiends!', 60586, 0, 0, 0, 'Stormwrought Ruins - Duke Balor IV - Aggro'),
(-1999965, 'Olivert... Philmore... Old friends...', 60587, 0, 0, 0, 'Stormwrought Ruins - Duke Balor IV - Death'),
(-1999966, 'I must kindly ask you to leave, the archives are not ready for public viewing!', 60634, 1, 0, 0, 'Stormwrought Ruins - Librarian Theodorus - Aggro'),
(-1999967, 'Behold, my signature attack! The great waves of Balor shall destroy you, once and for all!', 60635, 1, 0, 0, 'Stormwrought Ruins - Librarian Theodorus - Summon Enraged Sea Elemental'),
(-1999968, 'These pages were mine to organize... Such great effort, gone to waste!', 60636, 1, 0, 0, 'Stormwrought Ruins - Librarian Theodorus - Death'),
(-1999969, 'Let me tear your heart asunder!', 60595, 0, 0, 0, 'Stormwrought Ruins - Oronok Torn-Heart - Aggro'),
(-1999970, 'Gul''dan...! Your legacy...', 60596, 0, 0, 0, 'Stormwrought Ruins - Oronok Torn-Heart - Death'),
(-1999971, 'The dark sea will swallow your souls!', 60588, 0, 0, 0, 'Stormwrought Ruins - Chieftain Stormsong - Aggro'),
(-1999972, 'You know so little, whelps...', 60589, 0, 0, 0, 'Stormwrought Ruins - Chieftain Stormsong - Death'),
(-1999973, 'Step forth. Accept the cold embrace of death and drown in its bleakness!', 60597, 0, 0, 0, 'Stormwrought Ruins - Deathlord Tidebane - Aggro'),
(-1999974, 'Darkness shall come, and consume you all!', 60598, 0, 0, 0, 'Stormwrought Ruins - Deathlord Tidebane - Wail of Souls'),
(-1999975, 'The waves... they beckon me...', 60599, 0, 0, 0, 'Stormwrought Ruins - Deathlord Tidebane - Death'),
(-1999976, 'You shall be brought under heel intruder...', 60605, 0, 0, 0, 'Stormwrought Ruins - Subjugator Halthas Shadecrest - Aggro'),
(-1999977, 'My will is unbreakable, you shall bend your knee.', 60606, 0, 0, 0, 'Stormwrought Ruins - Subjugator Halthas Shadecrest - Dominate Mind'),
(-1999978, 'This cannot be! I was going to change the world!', 60607, 0, 0, 0, 'Stormwrought Ruins - Subjugator Halthas Shadecrest - Death'),
(-1999979, 'New toys, let''s hope you will not break so easily...', 60608, 0, 0, 0, 'Stormwrought Ruins - Lady Drazare - Aggro'),
(-1999980, 'Share your darkest secrets with me!', 60609, 0, 0, 0, 'Stormwrought Ruins - Lady Drazare - Dark Seduction'),
(-1999981, 'Impossible... You... vile...', 60610, 0, 0, 0, 'Stormwrought Ruins - Lady Drazare - Death'),
(-1999982, 'My master prepared me for this moment. Those ignorant to his truth will perish by my hands.', 60600, 1, 0, 0, 'Stormwrought Ruins - Ighalfor - Temple of Shadows'),
(-1999983, 'Your intrusion ends here!', 60601, 1, 0, 0, 'Stormwrought Ruins - Ighalfor - Aggro'),
(-1999984, 'Enough! The Bloodstone is ready; savor the last fleeting moments of your life!', 60602, 1, 0, 0, 'Stormwrought Ruins - Ighalfor - Channeling'),
(-1999985, 'Great Mergothid, lay your eyes upon this feast of souls!', 60603, 1, 0, 0, 'Stormwrought Ruins - Ighalfor - Mergothid Spawn'),
(-1999986, 'Too soon, incessant weakling. Your pathetic soul will be the compensation for your failure.', 60621, 1, 0, 0, 'Stormwrought Ruins - Mergothid - Release'),
(-1999987, 'More souls to feast upon!', 60622, 1, 0, 0, 'Stormwrought Ruins - Mergothid - 50% Health'),
(-1999988, 'The nether, calls yet again!', 60623, 1, 0, 0, 'Stormwrought Ruins - Mergothid - Death');

